        fileMode: FileDialog.SaveFile
        nameFilters: ["MP4 Video (*.mp4)", "MKV Video (*.mkv)", "All files (*)"]
        onAccepted: {
            root.selectedFile = fileDialog.selectedFile;
            // file:/// prefixを除去 (Linux/Windows対応)
            var path = root.selectedFile.toString();
            if (Qt.platform.os === "windows")
                path = path.replace(/^(file:\/{3})/, "");
            else
                path = path.replace(/^(file:\/\/)/, "");
            filePathField.text = path;
        }
    }

    ColumnLayout {
        anchors.fill: parent
        anchors.margins: 20
        spacing: 15

        RowLayout {
            TextField {
                id: filePathField

                Layout.fillWidth: true
                placeholderText: "保存先ファイルパス..."
                text: root.selectedFile
            }

            Button {
                text: "参照..."
                onClicked: fileDialog.open()
            }

        }

        // エンコード設定情報
        GroupBox {
            title: "出力設定 (プロジェクト設定同期)"
            Layout.fillWidth: true

            GridLayout {
                columns: 2
                rowSpacing: 10
                columnSpacing: 20

                Label {
                    text: "解像度:"
                }

                Label {
                    text: root.pWidth + " x " + root.pHeight
                    font.bold: true
                }

                Label {
                    text: "フレームレート:"
                }

                Label {
                    text: root.pFps.toFixed(2) + " fps"
                    font.bold: true
                }

                Label {
                    text: "コーデック:"
                }

                ComboBox {
                    id: codecCombo

                    model: root.codecModel.map((x) => {
                        return x.text;
                    })
                    currentIndex: 0
                }

                Label {
                    text: "品質 (Bitrate):"
                }

                SpinBox {
                    id: bitrateSpin

                    from: 1
                    to: 100
                    value: 15 // Mbps
                    editable: true
                    stepSize: 1
                    // suffixプロパティの代替実装
                    textFromValue: function(value, locale) {
                        return value + " Mbps";
                    }
                    valueFromText: function(text, locale) {
                        return Number.fromLocaleString(locale, text.replace(" Mbps", ""));
                    }
                }

            }

        }

        Item {
            Layout.fillHeight: true
        }

    }

}

import Qt.labs.platform as Platform
import QtQuick
import QtQuick.Controls
import QtQuick.Layouts
import QtQuick.Window
import "common" as Common

ApplicationWindow {
    id: mainWin

    visible: true
    width: 640
    height: 360
    x: 100
    y: 100
    title: "Rina - プレビュー"
    // お前はこれで死ねぇ！！！！！
    onClosing: (close) => {
        if (WindowManager)
            WindowManager.requestQuit();

        close.accepted = true;
    }
    // 起動時に自分自身(Window)をコントローラーに渡す
    Component.onCompleted: {
        if (TimelineBridge)
            TimelineBridge.setCompositeView(compositeView);

    }

    FontLoader {
        source: "qrc:/resources/remixicon.ttf"
    }

    // アクション定義 (ショートカット用)
    Action {
        id: newAction

        text: "新規プロジェクト"
        shortcut: "Ctrl+N"
        onTriggered: console.log("New Project")
    }

    Action {
        id: saveProjectAction // プロジェクトの上書き保存用アクション

        text: "プロジェクトの上書き保存"
        shortcut: "Ctrl+S"
        onTriggered: {
            if (TimelineBridge)
                TimelineBridge.saveProject("");

        }
    }

    Action {
        id: loadAction

        text: "プロジェクトを開く"
        shortcut: "Ctrl+O"
        onTriggered: loadDialog.open()
    }

    Action {
        id: saveAsProjectAction // プロジェクトを名前を付けて保存用アクション

        text: "プロジェクトを名前を付けて保存..."
        shortcut: "Ctrl+Shift+S"
        onTriggered: saveDialog.open()
    }

    Action {
        id: quitAction

        text: "終了"
        shortcut: "Ctrl+Q"
        onTriggered: {
            if (WindowManager)
                WindowManager.requestQuit();

        }
    }

    Action {
        id: undoAction

        text: "元に戻す"
        shortcut: "Ctrl+Z"
        onTriggered: {
            if (TimelineBridge)
                TimelineBridge.undo();

        }
    }

    Action {
        id: redoAction

        text: "やり直す"
        shortcut: "Ctrl+Shift+Z"
        onTriggered: {
            if (TimelineBridge)
                TimelineBridge.redo();

        }
    }

    Platform.MessageDialog {
        id: errorDialog

        title: "エラー"
        buttons: Platform.MessageDialog.Ok
    }

    Platform.MessageDialog {
        id: aboutDialog

        title: "Rinaについて"
        text: "Rina (Rolling Release)\n\nRina is not AviUtl.\n\nこのソフトウェアはGNU Affero General Public License Version 3に基づいて公開されています。\n\nhttps://codeberg.org/taisho-guy/Rina"
        buttons: Platform.MessageDialog.Ok
    }

    Connections {
        function onErrorOccurred(message) {
            errorDialog.text = message;
            errorDialog.open();
        }

        target: TimelineBridge
    }

    // FPSと再生速度の同期設定
    Binding {
        target: TimelineBridge ? TimelineBridge.transport : null
        property: "fps"
        value: (TimelineBridge && TimelineBridge.project) ? TimelineBridge.project.fps : 60
    }

    Connections {
        function onPlaybackSpeedChanged() {
            if (TimelineBridge)
                TimelineBridge.syncPlaybackSpeed();

        }

        target: TimelineBridge ? TimelineBridge.transport : null
    }

    Connections {
        function onSampleRateChanged() {
            if (TimelineBridge)
                TimelineBridge.updateAudioSampleRate();

        }

        target: TimelineBridge ? TimelineBridge.project : null
    }

    Platform.FileDialog {
        id: saveDialog

        fileMode: Platform.FileDialog.SaveFile
        nameFilters: ["Rina Project files (*.rina)", "JSON files (*.json)"]
        defaultSuffix: "rina"
        onAccepted: {
            if (TimelineBridge)
                TimelineBridge.saveProject(file);

        }
    }

    Platform.FileDialog {
        id: loadDialog

        fileMode: Platform.FileDialog.OpenFile
        nameFilters: ["Rina Project files (*.rina)", "JSON files (*.json)"]
        onAccepted: {
            if (TimelineBridge)
                TimelineBridge.loadProject(file);

        }
    }

    ExportDialog {
        id: exportDialog

        anchors.centerIn: parent
    }

    ColumnLayout {
        anchors.fill: parent
        spacing: 0

        CompositeView {
            id: compositeView

            Layout.fillWidth: true
            Layout.fillHeight: true
            // タイムラインウィンドウからレイヤー状態を取得
            getLayerVisible: function(layer) {
                var tlWin = WindowManager.getWindow("timeline");
                if (tlWin && tlWin.getLayerVisible)
                    return tlWin.getLayerVisible(layer);

                return true;
            }
        }

        // 再生コントロールバー
        Rectangle {
            Layout.fillWidth: true
            Layout.preferredHeight: 38
            color: mainWin.palette.window

            RowLayout {
                anchors.fill: parent
                anchors.leftMargin: 10
                anchors.rightMargin: 10
                spacing: 10

                // シークバー
                Slider {
                    id: seekSlider

                    Layout.fillWidth: true
                    from: 0
                    to: {
                        // クリップの末尾を取得して動的に拡張
                        var maxEnd = 0;
                        var clipList = (TimelineBridge && TimelineBridge.clips) ? TimelineBridge.clips : [];
                        for (var j = 0; j < clipList.length; j++) {
                            var clip = clipList[j];
                            var end = clip.startFrame + clip.durationFrames;
                            if (end > maxEnd)
                                maxEnd = end;

                        }
                        return Math.max(1, maxEnd + 1);
                    }
                    value: (TimelineBridge && TimelineBridge.transport) ? TimelineBridge.transport.currentFrame : 0
                    onMoved: {
                        if (TimelineBridge && TimelineBridge.transport)
                            TimelineBridge.transport.currentFrame = value;

                    }
                }

                Label {
                    text: Math.floor(seekSlider.value) + " / " + Math.floor(seekSlider.to)
                    font.pixelSize: 12
                    color: mainWin.palette.text
                }

                // 操作ボタン
                RowLayout {
                    spacing: 0

                    Button {
                        Layout.preferredWidth: 32
                        Layout.preferredHeight: 32
                        flat: true
                        onClicked: {
                            if (TimelineBridge && TimelineBridge.transport)
                                TimelineBridge.transport.currentFrame = Math.max(0, TimelineBridge.transport.currentFrame - 1);

                        }

                        contentItem: Common.RinaIcon {
                            iconName: "arrow_left_s_line"
                            size: 24
                            color: parent.hovered ? parent.palette.highlight : parent.palette.text
                        }

                    }

                    Button {
                        Layout.preferredWidth: 32
                        Layout.preferredHeight: 32
                        flat: true
                        onClicked: {
                            if (TimelineBridge && TimelineBridge.transport)
                                TimelineBridge.transport.togglePlay();

                        }

                        contentItem: Common.RinaIcon {
                            iconName: (TimelineBridge && TimelineBridge.transport && TimelineBridge.transport.isPlaying) ? "pause_fill" : "play_fill"
                            size: 24
                            color: parent.hovered ? parent.palette.highlight : parent.palette.text
                        }

                    }

                    Button {
                        Layout.preferredWidth: 32
                        Layout.preferredHeight: 32
                        flat: true
                        onClicked: {
                            if (TimelineBridge && TimelineBridge.transport)
                                TimelineBridge.transport.currentFrame = TimelineBridge.transport.currentFrame + 1;

                        }

                        contentItem: Common.RinaIcon {
                            iconName: "arrow_right_s_line"
                            size: 24
                            color: parent.hovered ? parent.palette.highlight : parent.palette.text
                        }

                    }

                }

                // 再生速度
                RowLayout {
                    spacing: 5

                    Label {
                        text: "速度"
                        color: mainWin.palette.text
                        font.pixelSize: 12
                    }

                    SpinBox {
                        from: 10
                        to: 400
                        stepSize: 10
                        editable: true
                        Layout.preferredWidth: 80
                        Layout.preferredHeight: 28
                        // 値のバインディング
                        value: (TimelineBridge && TimelineBridge.transport) ? Math.round(TimelineBridge.transport.playbackSpeed * 100) : 100
                        onValueModified: {
                            if (TimelineBridge && TimelineBridge.transport)
                                TimelineBridge.transport.playbackSpeed = value / 100;

                        }
                        textFromValue: function(value, locale) {
                            return (value / 100).toFixed(1) + "x";
                        }
                        valueFromText: function(text, locale) {
                            return Number.fromLocaleString(locale, text.replace("x", "")) * 100;
                        }
                    }

                }

            }

        }

    }

    // View3D の背後に黒背景を強制しない
    background: Rectangle {
        color: mainWin.palette.window
    }

    menuBar: MenuBar {
        Menu {
            title: "ファイル"

            Common.IconMenuItem {
                action: newAction
                iconName: "file_add_line"
            }

            Common.IconMenuItem {
                action: loadAction
                iconName: "folder_open_line"
            }

            MenuSeparator {
            }

            Common.IconMenuItem {
                action: saveProjectAction
                iconName: "save_line"
            }

            Common.IconMenuItem {
                action: saveAsProjectAction
                iconName: "save_3_line"
            }

            MenuSeparator {
            }

            Common.IconMenuItem {
                text: "メディアの書き出し..."
                iconName: "movie_line"
                enabled: TimelineBridge && TimelineBridge.project
                onTriggered: {
                    exportDialog.open();
                }
            }

            MenuSeparator {
            }

            Common.IconMenuItem {
                text: "環境設定"
                iconName: "settings_3_line"
                onTriggered: {
                    if (WindowManager)
                        WindowManager.systemSettingsVisible = true;

                }
            }

            MenuSeparator {
            }

            Common.IconMenuItem {
                text: "終了"
                action: quitAction
                iconName: "close_circle_line"
            }

        }

        Menu {
            title: "フィルタ"

            Common.IconMenuItem {
                text: "エフェクトの追加"
                iconName: "magic_line"
                enabled: TimelineBridge && TimelineBridge.selection && TimelineBridge.selection.selectedClipId >= 0
                onTriggered: {
                    if (WindowManager)
                        WindowManager.objectSettingsVisible = true;

                }
            }

        }

        Menu {
            title: "設定"

            Common.IconMenuItem {
                text: "サイズの変更"
                iconName: "aspect_ratio_line"
                onTriggered: {
                    if (WindowManager)
                        WindowManager.projectSettingsVisible = true;

                }
            }

            Common.IconMenuItem {
                text: "フレームレートの変更"
                iconName: "speed_line"
                onTriggered: {
                    if (WindowManager)
                        WindowManager.projectSettingsVisible = true;

                }
            }

            MenuSeparator {
            }

            Common.IconMenuItem {
                text: "環境設定"
                iconName: "settings_3_line"
                onTriggered: {
                    if (WindowManager)
                        WindowManager.systemSettingsVisible = true;

                }
            }

        }

        Menu {
