import QtQuick
import QtQuick.Controls
import QtQuick.Dialogs
import QtQuick.Layouts
import "common" as Common

Common.RinaWindow {
    id: root

    // プロジェクトが選択されたら他のウィンドウを開く
    signal projectSelected(string projectPath, int width, int height, double fps)

    width: 700
    height: 500
    title: "Rina - プロジェクトランチャー"
    Component.onCompleted: {
        // 最近使ったプロジェクトをロード
        if (SettingsManager && SettingsManager.settings) {
            var recent = SettingsManager.settings.recentProjects || [];
            recentModel.clear();
            for (var i = 0; i < Math.min(recent.length, 10); i++) {
                recentModel.append(recent[i]);
            }
            // 設定からデフォルト値を読み込む
            widthField.text = SettingsManager.settings.defaultProjectWidth || "1920";
            heightField.text = SettingsManager.settings.defaultProjectHeight || "1080";
            fpsField.text = SettingsManager.settings.defaultProjectFps || "60";
            sampleRateField.text = SettingsManager.settings.defaultProjectSampleRate || "48000";
            // テンプレートに応じて更新
            if (templateCombo.currentIndex !== 4)
                templateCombo.activated(templateCombo.currentIndex);

        }
    }

    FontLoader {
        source: "qrc:/resources/remixicon.ttf"
    }

    ListModel {
        id: recentModel
    }

    RowLayout {
        anchors.fill: parent
        anchors.margins: 20
        spacing: 20

        // 左側：新規プロジェクト
        ColumnLayout {
            Layout.fillHeight: true
            Layout.preferredWidth: parent.width * 0.45
            spacing: 15

            Label {
                text: "新規プロジェクト"
                font.pixelSize: 18
                font.bold: true
            }

            GroupBox {
                title: "プロジェクト設定"
                Layout.fillWidth: true

                GridLayout {
                    columns: 2
                    rowSpacing: 10
                    columnSpacing: 10
                    anchors.fill: parent

                    Label {
                        text: "テンプレート:"
                    }

                    ComboBox {
                        id: templateCombo

                        Layout.fillWidth: true
                        model: ["HD 1080p (1920x1080, 30fps)", "HD 720p (1280x720, 30fps)", "Full HD (1920x1080, 60fps)", "4K UHD (3840x2160, 30fps)", "カスタム"]
                        onActivated: (index) => {
                            switch (index) {
                            case 0:
                                widthField.text = "1920";
                                heightField.text = "1080";
                                fpsField.text = "30";
                                break;
                            case 1:
                                widthField.text = "1280";
                                heightField.text = "720";
                                fpsField.text = "30";
                                break;
                            case 2:
                                widthField.text = "1920";
                                heightField.text = "1080";
                                fpsField.text = "60";
                                break;
                            case 3:
                                widthField.text = "3840";
                                heightField.text = "2160";
                                fpsField.text = "30";
                                break;
                            default:
                                // カスタム
                                widthField.text = SettingsManager.settings.defaultProjectWidth || "1920";
                                heightField.text = SettingsManager.settings.defaultProjectHeight || "1080";
                                fpsField.text = SettingsManager.settings.defaultProjectFps || "60";
                                break;
                            }
                        }
                    }

                    Label {
                        text: "幅 (Width):"
                    }

                    TextField {
                        id: widthField

                        Layout.fillWidth: true

                        validator: IntValidator {
                            bottom: 1
                            top: 8000
                        }

                    }

                    Label {
                        text: "高さ (Height):"
                    }

                    TextField {
                        id: heightField

                        Layout.fillWidth: true

                        validator: IntValidator {
                            bottom: 1
                            top: 8000
                        }

                    }

                    Label {
                        text: "FPS:"
                    }

                    TextField {
                        id: fpsField

                        Layout.fillWidth: true

                        validator: DoubleValidator {
                            bottom: 1
                            top: 240
                        }

                    }

                    Label {
                        text: "サンプリングレート:"
                    }

                    TextField {
                        id: sampleRateField

                        Layout.fillWidth: true

                        validator: IntValidator {
                            bottom: 8000
                            top: 192000
                        }

                    }

                }

            }

            Button {
                id: newProjectBtn

                highlighted: true
                Layout.fillWidth: true
                onClicked: {
                    if (TimelineBridge && TimelineBridge.project)
                        TimelineBridge.project.sampleRate = parseInt(sampleRateField.text);

                    root.projectSelected("", parseInt(widthField.text), parseInt(heightField.text), parseFloat(fpsField.text));
                    root.close();
                }

                contentItem: RowLayout {
                    spacing: 8

                    Common.RinaIcon {
                        iconName: "file_add_line"
                        color: newProjectBtn.palette.buttonText
                    }

                    Text {
                        text: "新規プロジェクトを作成"
                        color: newProjectBtn.palette.buttonText
                        font: newProjectBtn.font
                    }

                }

            }

            Item {
                Layout.fillHeight: true
            }

        }

        // 右側：最近使ったプロジェクト
        ColumnLayout {
            Layout.fillHeight: true
            Layout.fillWidth: true
            spacing: 15

            Label {
                text: "最近使ったプロジェクト"
                font.pixelSize: 18
                font.bold: true
            }

            ScrollView {
                Layout.fillWidth: true
                Layout.fillHeight: true
                clip: true

                ListView {
                    id: recentListView

                    model: recentModel
                    spacing: 5

                    delegate: ItemDelegate {
                        width: recentListView.width
                        height: 60
                        onClicked: {
                            root.projectSelected(model.path, model.width, model.height, model.fps);
                            root.close();
                        }

                        ColumnLayout {
                            anchors.fill: parent
                            anchors.margins: 5

                            Label {
                                text: model.name || "無題のプロジェクト"
                                font.bold: true
                            }

                            Label {
                                text: model.path || ""
                                font.pixelSize: 10
                                color: "gray"
                            }

                            Label {
                                text: (model.width || 1920) + "x" + (model.height || 1080) + " @ " + (model.fps || 30) + "fps"
                                font.pixelSize: 10
                            }

                        }

                    }

                }

            }

            Button {
                id: openProjectBtn

                Layout.fillWidth: true
                onClicked: fileDialog.open()

                contentItem: RowLayout {
                    spacing: 8

                    Common.RinaIcon {
                        iconName: "folder_open_line"
                        color: openProjectBtn.palette.buttonText
                    }

                    Text {
                        text: "既存プロジェクトを開く..."
                        color: openProjectBtn.palette.buttonText
                        font: openProjectBtn.font
                    }

                }

            }

        }

    }

    FileDialog {
        id: fileDialog

        title: "プロジェクトファイルを開く"
        nameFilters: ["Rina Project (*.rina)", "All files (*)"]
        onAccepted: {
            var width = 1920;
            var height = 1080;
            var fps = 60;
            if (TimelineBridge) {
                var info = TimelineBridge.getProjectInfo(fileDialog.selectedFile);
                if (info.width !== undefined)
                    width = info.width;

                if (info.height !== undefined)
                    height = info.height;

                if (info.fps !== undefined)
                    fps = info.fps;

            }
            root.projectSelected(fileDialog.selectedFile, width, height, fps);
            root.close();
        }
    }

}

import QtQuick
import QtQuick.Controls
import QtQuick.Layouts
import "common" as Common

Common.RinaWindow {
    id: root

    width: 450
    height: 200
    title: "プロジェクト設定"
    // ウィンドウが表示されたときに現在の値をUIに反映
    onVisibleChanged: {
        if (visible && TimelineBridge && TimelineBridge.project) {
