                    v = rawEffectModels[i].evaluatedParam ? rawEffectModels[i].evaluatedParam("diffusion", relFrame) : undefined;

                if (v === undefined || v === null)
                    v = rawEffectModels[i].evaluatedParam ? rawEffectModels[i].evaluatedParam("strength", relFrame) : undefined;

                if (v === undefined || v === null)
                    v = rawEffectModels[i].params["size"] || rawEffectModels[i].params["diffusion"] || rawEffectModels[i].params["strength"];

                // FastBlurの特性上、半径の3倍程度の余白がないと端が切れて不自然になるため広めに確保する
                return Number(v || 0) * 3;
            }
        }
        return 0;
    }

    // NodeのプロパティをtransformModelにバインド
    position: hasTransform ? transformLoader.item.outputPosition : Qt.vector3d(0, 0, 0)
    eulerRotation: hasTransform ? transformLoader.item.outputRotation : Qt.vector3d(0, 0, 0)
    pivot: hasTransform ? transformLoader.item.outputPivot : Qt.vector3d(0, 0, 0)
    scale: Qt.vector3d(1, 1, 1) // 下のModelで個別に設定
    // renderHost が後からセットされても確実に移送する
    onRenderHostChanged: {
        adopt2D(sourceItem);
        adopt2D(rendererInstance);
        adopt2D(_fbCaptureItemImpl);
    }
    Component.onCompleted: {
        // 各オブジェクト(TextObject/RectObject)が set してくる sourceItem を移す
        adopt2D(base.sourceItem);
        // ObjectRenderer(= ShaderEffectSource/effectsチェーン)も移す
        adopt2D(rendererInstance);
        adopt2D(_fbCaptureItemImpl);
    }
    Component.onDestruction: {
        for (var i = 0; i < owned2D.length; i++) {
            try {
                if (owned2D[i])
                    owned2D[i].destroy();

            } catch (e) {
            }
        }
        owned2D = [];
    }
    // sourceItem は常に非表示（renderer.output のみ表示）
    onSourceItemChanged: {
        if (sourceItem) {
            // キャプチャ安定化のためvisibleは落とさず、不可視化はopacityで行う
            sourceItem.visible = true;
            sourceItem.opacity = 1;
        }
    }
    onRelFrameChanged: {
        if (hasTransform)
            transformLoader.item.frame = relFrame;

    }

    // --- transformエフェクトのインスタンス化 ---
    Loader {
        id: transformLoader

        source: (root.transformModel && root.transformModel.qmlSource) ? root.transformModel.qmlSource : ""
        // BaseEffectのプロパティを注入
        onLoaded: {
            item.source = null; // Transformはsourceを持たない
            item.params = root.transformModel.params;
            item.effectModel = root.transformModel;
            item.frame = root.relFrame;
        }
    }

    Connections {
        function onParamsChanged() {
            _tmRev++;
        }

        function onKeyframeTracksChanged() {
            _tmRev++;
        }

        target: transformModel
        ignoreUnknownSignals: true
    }

    Connections {
        function onClipEffectsChanged(changedClipId) {
            if (changedClipId === clipId)
                rawEffectModels = TimelineBridge.getClipEffectsModel(clipId);

        }

        function onClipsChanged() {
            rawEffectModels = TimelineBridge.getClipEffectsModel(clipId);
        }

        target: TimelineBridge
    }

    // ─── 2D変換済みキャプチャアイテム ─────────────────────────────
    // View3D の clipNode が持つ transform を 2D 空間で再現し、
    // FB が「変換後の最終見た目」を収集できるようにする
    Item {
        id: _fbCaptureItemImpl

        width: (TimelineBridge && TimelineBridge.project) ? TimelineBridge.project.width : 1920
        height: (TimelineBridge && TimelineBridge.project) ? TimelineBridge.project.height : 1080
        visible: true // SceneGraph に残すため true (opacity は renderHost 側で 0)

        Item {
            id: fbTransformItem

            // Transform.qmlのインスタンスから値を取得
            readonly property var _ti: base.hasTransform ? transformLoader.item : null

            // テクスチャサイズをスケール適用後のサイズに設定
            width: (renderer.output.sourceItem ? renderer.output.sourceItem.width : 1) * (_ti ? _ti.output2dScale : 1)
            height: (renderer.output.sourceItem ? renderer.output.sourceItem.height : 1) * (_ti ? _ti.output2dScale : 1)
            // AviUtl 座標系: 中心(0,0)、Y下プラス → Qt2D: 中心 = parent の center + offset
            x: _fbCaptureItemImpl.width / 2 + (_ti ? _ti.output2dX : 0) - width / 2
            y: _fbCaptureItemImpl.height / 2 - (_ti ? _ti.output2dY : 0) - height / 2
            rotation: -(_ti ? _ti.output2dRotationZ : 0)
            opacity: _ti ? _ti.outputOpacity : 1

            ShaderEffectSource {
                anchors.fill: parent
                sourceItem: renderer.finalItem
                live: true
                hideSource: true // finalItem (opacity:0 かもしれないが) を隠す
            }

        }

    }

    // レンダラー自動配置
    Common.ObjectRenderer {
        id: rendererInstance

        originalSource: base.sourceItem
        effectModels: base.filterModels
        relFrame: base.relFrame
    }

    sourceItem: Item {
        // デフォルトはダミー（visible: falseは子側で設定）
        width: 1
        height: 1
    }

}

import "." as Common // 同じディレクトリ内のコンポーネント(ParamControl)を参照
import QtQuick
import QtQuick.Controls
import QtQuick.Dialogs
import QtQuick.Layouts

Loader {
    // ===============================================
    //               Components
    // ===============================================
    // アニメーション可能な数値 (ParamControl)
    // 単一の整数値 (シーンIDなど、イージング不可)
    // 色選択
    // 真偽値 (チェックボックス)
    // ファイルパス (ファイル選択ボタン付き)
    // 文字列
    // 列挙型 (コンボボックス)
    // コンボボックス (動的ソース)
    // ヘッダー (区切り線)

    id: controlLoader

    // === 入力プロパティ ===
    // 定義オブジェクト: { type: "float", name: "opacity", label: "不透明度", min: 0, max: 1, ... }
    property var definition: ({
    })
    // 現在の値 (バインディング可能)
    property var value: null

    // === 出力シグナル ===
    signal valueModified(var newValue)
    // 追加: ParamControlの中央ボタンクリック（イージング設定など）を親に伝えるシグナル
    signal paramButtonClicked()

    // === コンポーネント選択ロジック ===
    sourceComponent: {
        if (!definition)
            return unknownComponent;

        switch (definition.type) {
        case "float":
        case "number":
        case "slider":
        case "spinner":
            return floatComponent;
        case "int":
        case "integer":
        case "scene_id":
            return intComponent;
        case "color":
            return colorComponent;
        case "bool":
        case "boolean":
            return boolComponent;
        case "path":
        case "file":
            return pathComponent;
        case "string":
        case "text":
            return stringComponent;
        case "enum":
            return enumComponent;
        case "combo":
            return comboComponent;
        case "font":
            return fontComponent;
        case "header":
            return headerComponent;
        default:
            // デフォルト
            return unknownComponent;
        }
    }

    // --- 1. Float / Number (ParamControl) ---
    // アニメーション、イージング、中間点に対応した高機能スライダー
    Component {
        id: floatComponent

        Common.ParamControl {
            paramName: (controlLoader.definition.label && controlLoader.definition.label !== "") ? controlLoader.definition.label : (controlLoader.definition.param || controlLoader.definition.name || "Param")
            // 値の初期化 (null/undefinedチェック)
            startValue: (controlLoader.value !== undefined && controlLoader.value !== null) ? Number(controlLoader.value) : (controlLoader.definition.default || 0)
            // ※ 現状のControlLoaderは単一値(value)しか受け取っていないため、endValueはstartValueと同じにするか、
            //    将来的にControlLoader自体がstart/endを受け取るように拡張する必要がある。
            //    ここでは「現在値」を表示する簡易実装とする。
            endValue: startValue
            isRangeMode: false
            minValue: controlLoader.definition.min !== undefined ? controlLoader.definition.min : -100000
            maxValue: controlLoader.definition.max !== undefined ? controlLoader.definition.max : 100000
            decimals: 2
            // ControlLoaderは単一の値を返すラッパーとして振る舞う
            onStartValueModified: function(val) {
                controlLoader.valueModified(val);
            }
            onEndValueModified: function(val) {
                // 将来的にはここで終了値を別のプロパティとして書き戻す
                // 現状はstartと同じ扱いにするか、無視する
                controlLoader.valueModified(val);
            }
            // 追加: ボタンクリックイベントの転送
            onParamButtonClicked: {
                controlLoader.paramButtonClicked();
            }
        }

    }

    // --- 2. Int / Scene ID ---
    // アニメーションしない単純な整数入力
    Component {
        id: intComponent

        RowLayout {
            spacing: 8

            Label {
                text: (controlLoader.definition.label && controlLoader.definition.label !== "") ? controlLoader.definition.label : (controlLoader.definition.param || controlLoader.definition.name || "Param")
                color: "white"
                Layout.preferredWidth: 80
                elide: Text.ElideRight
            }

            TextField {
                text: String(controlLoader.value !== undefined ? controlLoader.value : (controlLoader.definition.default || 0))
                Layout.preferredWidth: 80
                horizontalAlignment: TextInput.AlignRight
                selectByMouse: true
                onEditingFinished: {
                    var val = parseInt(text);
                    if (!isNaN(val))
                        controlLoader.valueModified(val);

                }

                validator: IntValidator {
                    bottom: controlLoader.definition.min !== undefined ? controlLoader.definition.min : -2.14748e+09
                    top: controlLoader.definition.max !== undefined ? controlLoader.definition.max : 2.14748e+09
                }

            }

            // 単位などのラベルがあれば表示
            Label {
                text: controlLoader.definition.unit || ""
                color: "#888"
                visible: text.length > 0
            }

            // Spacer
            Item {
                Layout.fillWidth: true
            }

        }

    }

    // --- 3. Color ---
    Component {
        id: colorComponent

        RowLayout {
            spacing: 8

            ColorDialog {
                id: colorDialog

                selectedColor: controlLoader.value || "#FFFFFF"
                onAccepted: controlLoader.valueModified(selectedColor.toString())
            }

            Label {
                text: (controlLoader.definition.label && controlLoader.definition.label !== "") ? controlLoader.definition.label : (controlLoader.definition.param || controlLoader.definition.name || "Param")
                color: "white"
                Layout.preferredWidth: 80
            }

            Rectangle {
                width: 60
                height: 24
                color: controlLoader.value || "#FFFFFF"
                border.color: "white"
                border.width: 1
                radius: 2

                MouseArea {
                    anchors.fill: parent
                    onClicked: {
                        colorDialog.open();
                    }
                }

            }

            // HEX値の直接入力
            TextField {
                text: controlLoader.value || "#FFFFFF"
                Layout.preferredWidth: 80
                selectByMouse: true
                onEditingFinished: {
                    controlLoader.valueModified(text);
                }
            }

        }

    }

    // --- 4. Bool (Checkbox) ---
    Component {
        id: boolComponent

        RowLayout {
            spacing: 8

            Label {
                text: (controlLoader.definition.label && controlLoader.definition.label !== "") ? controlLoader.definition.label : (controlLoader.definition.param || controlLoader.definition.name || "Param")
                color: "white"
                Layout.preferredWidth: 80
            }

            CheckBox {
                checked: controlLoader.value === true
                text: checked ? "On" : "Off"
                onCheckedChanged: {
                    controlLoader.valueModified(checked);
                }
            }

        }

    }

    // --- 5. Path / File ---
    Component {
        id: pathComponent

        RowLayout {
            spacing: 8

            FileDialog {
                id: fileDialog

                title: controlLoader.definition.label || "ファイルを選択"
                currentFile: (controlLoader.value && controlLoader.value.toString() !== "") ? (controlLoader.value.toString().startsWith("file://") ? controlLoader.value : "file://" + controlLoader.value) : ""
                nameFilters: {
                    var f = controlLoader.definition.filter;
                    if (Array.isArray(f))
                        return f;

                    return f ? [f, "All files (*)"] : ["All files (*)"];
                }
                onAccepted: {
                    var path = selectedFile.toString();
                    if (Qt.platform.os === "windows")
                        path = path.replace(/^(file:\/{3})/, "");
                    else
                        path = path.replace(/^(file:\/\/)/, "");
                    controlLoader.valueModified(path);
                }
            }

            Label {
                text: (controlLoader.definition.label && controlLoader.definition.label !== "") ? controlLoader.definition.label : (controlLoader.definition.param || controlLoader.definition.name || "Param")
                color: "white"
                Layout.preferredWidth: 80
            }

            TextField {
                text: String(controlLoader.value || "")
                Layout.fillWidth: true
                selectByMouse: true
                onEditingFinished: {
                    controlLoader.valueModified(text);
                }
            }

            Button {
                text: "..."
                Layout.preferredWidth: 30
                onClicked: {
                    fileDialog.open();
                }
            }

        }

    }

    // --- 6. String / Text ---
    Component {
        id: stringComponent

        RowLayout {
            spacing: 8

            Label {
                text: (controlLoader.definition.label && controlLoader.definition.label !== "") ? controlLoader.definition.label : (controlLoader.definition.param || controlLoader.definition.name || "Param")
                color: "white"
                Layout.preferredWidth: 80
            }

            TextField {
                text: String(controlLoader.value || "")
                Layout.fillWidth: true
                selectByMouse: true
                onEditingFinished: {
                    controlLoader.valueModified(text);
                }
            }

        }

    }

    // --- 7. Enum (ComboBox) ---
    Component {
        id: enumComponent

        RowLayout {
            spacing: 8

            Label {
                text: (controlLoader.definition.label && controlLoader.definition.label !== "") ? controlLoader.definition.label : (controlLoader.definition.param || controlLoader.definition.name || "Param")
                color: "white"
                Layout.preferredWidth: 80
            }

            ComboBox {
                model: controlLoader.definition.options || []
                Layout.fillWidth: true
                // 現在の値(文字列)に対応するインデックスを探す
                currentIndex: {
                    var idx = model.indexOf(controlLoader.value);
                    return idx >= 0 ? idx : 0;
                }
                onActivated: {
                    // ユーザー操作時のみ発火
                    controlLoader.valueModified(currentText);
                }
            }

        }

    }

    // --- 9. Combo (Dynamic Source) ---
    Component {
        id: comboComponent

        RowLayout {
            spacing: 8

            Label {
                text: (controlLoader.definition.label && controlLoader.definition.label !== "") ? controlLoader.definition.label : (controlLoader.definition.param || controlLoader.definition.name || "Param")
                color: "white"
                Layout.preferredWidth: 80
            }

            ComboBox {
                id: combo

                // ソースの解決 (TimelineBridge等)
                property var sourceObj: {
                    if (controlLoader.definition.source === "TimelineBridge")
                        return TimelineBridge;

                    return null;
                }

                Layout.fillWidth: true
                model: sourceObj ? sourceObj[controlLoader.definition.sourceProperty] : []
                textRole: controlLoader.definition.textRole || "name"
                valueRole: controlLoader.definition.valueRole || "id"
                // 現在値の反映
                currentIndex: {
                    var val = controlLoader.value;
                    if (!model)
                        return -1;

                    for (var i = 0; i < count; i++) {
                        var item = model[i];
                        if (item && item[valueRole] == val)
                            return i;

                    }
                    return -1;
                }
                onActivated: (index) => {
                    if (index >= 0 && model && model[index])
                        controlLoader.valueModified(model[index][valueRole]);

                }
            }

        }

    }

    // --- font: FontDialog ベースフォントピッカー ─────────────────────
    Component {
        id: fontComponent

        RowLayout {
            Layout.fillWidth: true
            spacing: 6

            FontDialog {
                id: fontPickerDialog

                title: controlLoader.definition.label || "フォントを選択"
                // 現在値をダイアログの初期選択に反映
                currentFont.family: controlLoader.value || ""
                onAccepted: controlLoader.valueModified(selectedFont.family)
            }

            Label {
                text: (controlLoader.definition.label && controlLoader.definition.label !== "") ? controlLoader.definition.label : (controlLoader.definition.param || controlLoader.definition.name || "Param")
                color: "white"
                Layout.preferredWidth: 80
                elide: Text.ElideRight
            }

            // 現在のフォント名を表示 + クリックでダイアログを開く
            Button {
                Layout.fillWidth: true
                text: controlLoader.value ? controlLoader.value : "デフォルト"
                // ボタン自体をそのフォントでプレビュー表示
                font.family: controlLoader.value || ""
                font.pixelSize: 13
                onClicked: fontPickerDialog.open()
            }

        }

    }

    // --- 8. Header ---
    Component {
        id: headerComponent

        ColumnLayout {
            Layout.fillWidth: true
            Layout.topMargin: 12
            Layout.bottomMargin: 4

            Label {
                text: controlLoader.definition.label || "Settings"
                font.bold: true
                font.pixelSize: 13
                color: "#cccccc"
            }

            Rectangle {
                Layout.fillWidth: true
                height: 1
                color: "#444444"
            }

        }

    }

    // --- Fallback ---
    Component {
        id: unknownComponent

        Text {
            text: "Unknown Type: " + (controlLoader.definition ? controlLoader.definition.type : "null")
            color: "red"
            font.pixelSize: 10
        }

    }

}

import QtQuick
import QtQuick.Controls
import QtQuick.Layouts

Dialog {
    id: root

    property var effectModel: null
    property string paramName: ""
    property int keyframeFrame: 0
    property string selectedType: "linear"
    // [cp1x, cp1y, cp2x, cp2y, endX, endY, ...]
    property var bezierParams: [0.33, 0, 0.66, 1, 1, 1]

    function requestPreview() {
        if (previewCanvas)
            previewCanvas.requestPaint();

    }

    title: "イージング設定: " + paramName + " [" + selectedType + "]"
    modal: true
    standardButtons: Dialog.Ok | Dialog.Cancel
    onSelectedTypeChanged: requestPreview()
    onBezierParamsChanged: requestPreview()
    onOpened: {
        if (!effectModel)
            return ;

        typeCombo.model = effectModel.availableEasings();
        const tracks = effectModel.keyframeTracks;
        const track = tracks ? tracks[paramName] : undefined;
        if (!track)
            return ;

        for (let i = 0; i < track.length; i++) {
            if (track[i].frame === keyframeFrame) {
                const kf = track[i];
                selectedType = kf.interp || "linear";
                // 旧データ後方互換: bezier → custom へ昇格
                if (selectedType === "bezier")
                    selectedType = "custom";

                var idx = typeCombo.model.indexOf(selectedType);
                typeCombo.currentIndex = idx >= 0 ? idx : 0;
                if (selectedType === "custom") {
                    if (kf.points && kf.points.length >= 6) {
                        var pts = [];
                        for (let j = 0; j < kf.points.length; ++j) pts.push(kf.points[j])
                        bezierParams = pts;
                    } else {
                        // 旧 bezier 形式を custom 6要素形式に変換
                        bezierParams = [kf.bzx1 !== undefined ? kf.bzx1 : 0.33, kf.bzy1 !== undefined ? kf.bzy1 : 0, kf.bzx2 !== undefined ? kf.bzx2 : 0.66, kf.bzy2 !== undefined ? kf.bzy2 : 1, 1, 1];
                    }
                }
                break;
            }
        }
        requestPreview();
    }
    onAccepted: {
        if (!effectModel)
            return ;

        const kf = effectModel.keyframeTracks[paramName].find(function(k) {
            return k.frame === keyframeFrame;
        });
        if (!kf)
            return ;

        let options = {
            "interp": selectedType
        };
        if (selectedType === "custom") {
            var pts = [];
            for (let j = 0; j < bezierParams.length; ++j) pts.push(bezierParams[j])
            options.points = pts;
        }
        effectModel.setKeyframe(paramName, keyframeFrame, kf.value, options);
    }

    ColumnLayout {
        spacing: 15

        RowLayout {
            Label {
                text: "種類:"
            }

            ComboBox {
                id: typeCombo

                model: ["linear"]
                onActivated: function(idx) {
                    root.selectedType = typeCombo.currentText;
                }
            }

        }

        GroupBox {
            title: "カーブプレビュー"
            Layout.fillWidth: true

            Item {
                implicitWidth: 320
                implicitHeight: 160
                Layout.fillWidth: true

                Canvas {
                    id: previewCanvas

                    // ハンドルのピクセル座標を返す [[px,py], ...]
                    function handlePositions() {
                        var bz = root.bezierParams;
                        var w = width, h = height;
                        var result = [];
                        var prevX = 0, prevY = 0;
                        for (var i = 0; i < bz.length; i += 6) {
                            result.push([bz[i] * w, (1 - bz[i + 1]) * h]); // cp1
                            result.push([bz[i + 2] * w, (1 - bz[i + 3]) * h]); // cp2
                            // 最終セグメントでなければ anchorPoint も移動可能
                            if (i + 6 < bz.length)
                                result.push([bz[i + 4] * w, (1 - bz[i + 5]) * h]);

                            // anchor
                            prevX = bz[i + 4];
                            prevY = bz[i + 5];
                        }
                        return result;
                    }

                    // evalEasing はここでクロージャとして定義 (bz をキャプチャ)
                    function evalEasing(t) {
                        // ─── Bounce ────────────────────────────────
                        function _bounceOut(x) {
                            var n1 = 7.5625, d1 = 2.75;
                            if (x < 1 / d1)
                                return n1 * x * x;

                            if (x < 2 / d1) {
                                x -= 1.5 / d1;
                                return n1 * x * x + 0.75;
                            }
                            if (x < 2.5 / d1) {
                                x -= 2.25 / d1;
                                return n1 * x * x + 0.9375;
                            }
                            x -= 2.625 / d1;
                            return n1 * x * x + 0.984375;
                        }

                        var type = root.selectedType.toLowerCase().replace(/_/g, "");
                        // ─── Sine ──────────────────────────────────
                        if (type === "easeinsine")
                            return 1 - Math.cos(t * Math.PI / 2);

                        if (type === "easeoutsine")
                            return Math.sin(t * Math.PI / 2);

                        if (type === "easeinoutsine")
                            return -(Math.cos(Math.PI * t) - 1) / 2;

                        // ─── Quad ──────────────────────────────────
                        if (type === "easein" || type === "easeinquad")
                            return t * t;

                        if (type === "easeout" || type === "easeoutquad")
                            return 1 - (1 - t) * (1 - t);

                        if (type === "easeinout" || type === "easeinoutquad")
                            return t < 0.5 ? 2 * t * t : 1 - ((-2 * t + 2) * (-2 * t + 2)) / 2;

                        // ─── Cubic ─────────────────────────────────
                        if (type === "easeincubic")
                            return t * t * t;

                        if (type === "easeoutcubic")
                            return 1 - (1 - t) * (1 - t) * (1 - t);

                        if (type === "easeinoutcubic")
                            return t < 0.5 ? 4 * t * t * t : 1 - ((-2 * t + 2) * (-2 * t + 2) * (-2 * t + 2)) / 2;

                        // ─── Quart ─────────────────────────────────
                        if (type === "easeinquart")
                            return t * t * t * t;

                        if (type === "easeoutquart")
                            return 1 - (1 - t) * (1 - t) * (1 - t) * (1 - t);

                        if (type === "easeinoutquart")
                            return t < 0.5 ? 8 * t * t * t * t : 1 - ((-2 * t + 2) * (-2 * t + 2) * (-2 * t + 2) * (-2 * t + 2)) / 2;

                        // ─── Quint ─────────────────────────────────
                        if (type === "easeinquint")
                            return t * t * t * t * t;

                        if (type === "easeoutquint")
                            return 1 - (1 - t) * (1 - t) * (1 - t) * (1 - t) * (1 - t);

                        if (type === "easeinoutquint")
                            return t < 0.5 ? 16 * t * t * t * t * t : 1 - ((-2 * t + 2) * (-2 * t + 2) * (-2 * t + 2) * (-2 * t + 2) * (-2 * t + 2)) / 2;

                        // ─── Expo ──────────────────────────────────
                        if (type === "easeinexpo")
                            return t === 0 ? 0 : Math.pow(2, 10 * t - 10);

                        if (type === "easeoutexpo")
                            return t === 1 ? 1 : 1 - Math.pow(2, -10 * t);

                        if (type === "easeinoutexpo") {
                            if (t === 0)
                                return 0;

                            if (t === 1)
                                return 1;

                            return t < 0.5 ? Math.pow(2, 20 * t - 10) / 2 : (2 - Math.pow(2, -20 * t + 10)) / 2;
                        }
                        // ─── Circ ──────────────────────────────────
                        if (type === "easeincirc")
                            return 1 - Math.sqrt(1 - t * t);

                        if (type === "easeoutcirc")
                            return Math.sqrt(1 - (t - 1) * (t - 1));

                        if (type === "easeinoutcirc")
                            return t < 0.5 ? (1 - Math.sqrt(1 - 4 * t * t)) / 2 : (Math.sqrt(1 - (-2 * t + 2) * (-2 * t + 2)) + 1) / 2;

                        // ─── Back ──────────────────────────────────
                        if (type === "easeinback") {
                            var c1 = 1.70158, c3 = c1 + 1;
                            return c3 * t * t * t - c1 * t * t;
                        }
                        if (type === "easeoutback") {
                            var c1b = 1.70158, c3b = c1b + 1;
                            return 1 + c3b * (t - 1) * (t - 1) * (t - 1) + c1b * (t - 1) * (t - 1);
                        }
                        if (type === "easeinoutback") {
                            var c2 = 1.70158 * 1.525;
                            return t < 0.5 ? ((2 * t) * (2 * t) * ((c2 + 1) * 2 * t - c2)) / 2 : ((2 * t - 2) * (2 * t - 2) * ((c2 + 1) * (2 * t - 2) + c2) + 2) / 2;
                        }
                        // ─── Elastic ───────────────────────────────
                        if (type === "easeinelastic") {
                            var c4 = 2 * Math.PI / 3;
                            if (t === 0)
                                return 0;

                            if (t === 1)
                                return 1;

                            return -Math.pow(2, 10 * t - 10) * Math.sin((10 * t - 10.75) * c4);
                        }
                        if (type === "easeoutelastic") {
                            var c4e = 2 * Math.PI / 3;
                            if (t === 0)
                                return 0;

                            if (t === 1)
                                return 1;

                            return Math.pow(2, -10 * t) * Math.sin((10 * t - 0.75) * c4e) + 1;
                        }
                        if (type === "easeinoutelastic") {
                            var c5 = 2 * Math.PI / 4.5;
                            if (t === 0)
                                return 0;

                            if (t === 1)
                                return 1;

                            return t < 0.5 ? -(Math.pow(2, 20 * t - 10) * Math.sin((20 * t - 11.125) * c5)) / 2 : (Math.pow(2, -20 * t + 10) * Math.sin((20 * t - 11.125) * c5)) / 2 + 1;
                        }
                        if (type === "easeoutbounce")
                            return _bounceOut(t);

                        if (type === "easeinbounce")
                            return 1 - _bounceOut(1 - t);

                        if (type === "easeinoutbounce")
                            return t < 0.5 ? (1 - _bounceOut(1 - 2 * t)) / 2 : (1 + _bounceOut(2 * t - 1)) / 2;

                        // ─── カスタムベジェ (既存実装そのまま) ─────
                        if (type === "custom") {
                            var prevX = 0, prevY = 0;
                            for (var i = 0; i < bz.length; i += 6) {
                                var cp1x = bz[i], cp1y = bz[i + 1];
                                var cp2x = bz[i + 2], cp2y = bz[i + 3];
                                var endX = bz[i + 4], endY = bz[i + 5];
                                if (t <= endX || i + 6 >= bz.length) {
                                    var range = endX - prevX;
                                    if (range < 0.0001)
                                        return endY;

                                    var nx = (t - prevX) / range;
                                    var nc1x = (cp1x - prevX) / range;
                                    var nc2x = (cp2x - prevX) / range;
                                    var T = nx;
                                    for (var k = 0; k < 8; k++) {
                                        var u = 1 - T;
                                        var cx = 3 * u * u * T * nc1x + 3 * u * T * T * nc2x + T * T * T;
                                        var err = cx - nx;
                                        if (Math.abs(err) < 0.0001)
                                            break;

                                        var dcx = 3 * u * u * nc1x + 6 * u * T * (nc2x - nc1x) + 3 * T * T * (1 - nc2x);
                                        if (Math.abs(dcx) < 1e-06)
                                            break;

                                        T -= err / dcx;
                                    }
                                    T = Math.max(0, Math.min(1, T));
                                    var u2 = 1 - T;
                                    return u2 * u2 * u2 * prevY + 3 * u2 * u2 * T * cp1y + 3 * u2 * T * T * cp2y + T * T * T * endY;
                                }
                                prevX = endX;
                                prevY = endY;
                            }
                        }
                        return t;
                    }

                    anchors.fill: parent
                    onPaint: {
                        var ctx = getContext("2d");
                        var w = width, h = height;
                        ctx.clearRect(0, 0, w, h);
                        // 背景
                        ctx.fillStyle = "#222";
                        ctx.fillRect(0, 0, w, h);
                        // グリッド
                        ctx.strokeStyle = "#444";
                        ctx.lineWidth = 0.5;
                        for (var i = 1; i < 4; i++) {
                            ctx.beginPath();
                            ctx.moveTo(w * (i / 4), 0);
                            ctx.lineTo(w * (i / 4), h);
                            ctx.stroke();
                            ctx.beginPath();
                            ctx.moveTo(0, h * (i / 4));
                            ctx.lineTo(w, h * (i / 4));
                            ctx.stroke();
                        }
                        // 対角線（linear 参照）
                        ctx.strokeStyle = "#555";
                        ctx.lineWidth = 1;
                        ctx.beginPath();
                        ctx.moveTo(0, h);
                        ctx.lineTo(w, 0);
                        ctx.stroke();
                        var bz = root.bezierParams;
                        // 青い曲線
                        ctx.strokeStyle = "#48f";
                        ctx.lineWidth = 2;
                        ctx.beginPath();
                        for (var s = 0; s <= 64; s++) {
                            var t = s / 64;
                            var y = evalEasing(t);
                            var px = t * w;
                            var py = h - Math.max(0, Math.min(1, y)) * h;
                            s === 0 ? ctx.moveTo(px, py) : ctx.lineTo(px, py);
                        }
                        ctx.stroke();
                        // custom のときハンドルとタンジェントラインを描画
                        if (root.selectedType === "custom") {
                            var prevAnchorX = 0, prevAnchorY = h;
                            for (var seg = 0; seg < bz.length; seg += 6) {
                                var c1px = bz[seg] * w, c1py = (1 - bz[seg + 1]) * h;
                                var c2px = bz[seg + 2] * w, c2py = (1 - bz[seg + 3]) * h;
                                var enpx = bz[seg + 4] * w, enpy = (1 - bz[seg + 5]) * h;
                                // タンジェントライン
                                ctx.strokeStyle = "#888";
                                ctx.lineWidth = 0.8;
                                ctx.setLineDash([3, 3]);
                                ctx.beginPath();
                                ctx.moveTo(prevAnchorX, prevAnchorY);
                                ctx.lineTo(c1px, c1py);
                                ctx.stroke();
                                ctx.beginPath();
                                ctx.moveTo(enpx, enpy);
                                ctx.lineTo(c2px, c2py);
                                ctx.stroke();
                                ctx.setLineDash([]);
                                // cp1 ハンドル (白丸)
                                ctx.fillStyle = "#fff";
                                ctx.beginPath();
                                ctx.arc(c1px, c1py, 5, 0, 2 * Math.PI);
                                ctx.fill();
                                // cp2 ハンドル (白丸)
                                ctx.fillStyle = "#fff";
                                ctx.beginPath();
                                ctx.arc(c2px, c2py, 5, 0, 2 * Math.PI);
                                ctx.fill();
                                // anchor ハンドル (黄丸、始点/終点以外)
                                if (seg + 6 < bz.length) {
                                    ctx.fillStyle = "#ff0";
                                    ctx.beginPath();
                                    ctx.arc(enpx, enpy, 6, 0, 2 * Math.PI);
                                    ctx.fill();
                                }
                                prevAnchorX = enpx;
                                prevAnchorY = enpy;
                            }
                        }
                    }
                }

                // ドラッグ編集用 MouseArea
                MouseArea {
                    property int dragIdx: -1 // bezierParams内のインデックス
                    property bool isDragAnchor: false

                    function findNearestHandle(mx, my) {
                        var bz = root.bezierParams;
                        var w = previewCanvas.width, h = previewCanvas.height;
                        var best = -1, bestDist = 12 * 12; // 12px ヒット半径
                        var prevX = 0, prevY = 0;
                        for (var seg = 0; seg < bz.length; seg += 6) {
                            // cp1
                            var dx = mx - bz[seg] * w, dy = my - (1 - bz[seg + 1]) * h;
                            if (dx * dx + dy * dy < bestDist) {
                                bestDist = dx * dx + dy * dy;
                                best = seg;
                            }
                            // cp2
                            dx = mx - bz[seg + 2] * w;
                            dy = my - (1 - bz[seg + 3]) * h;
                            if (dx * dx + dy * dy < bestDist) {
                                bestDist = dx * dx + dy * dy;
                                best = seg + 2;
                            }
                            // anchor (中間のみ)
                            if (seg + 6 < bz.length) {
                                dx = mx - bz[seg + 4] * w;
                                dy = my - (1 - bz[seg + 5]) * h;
                                if (dx * dx + dy * dy < bestDist) {
                                    bestDist = dx * dx + dy * dy;
                                    best = seg + 4;
                                }
                            }
                        }
                        return best;
                    }

                    anchors.fill: parent
                    enabled: root.selectedType === "custom"
                    onPressed: function(mouse) {
                        dragIdx = findNearestHandle(mouse.x, mouse.y);
                    }
                    onPositionChanged: function(mouse) {
                        if (dragIdx < 0)
                            return ;

                        var w = previewCanvas.width, h = previewCanvas.height;
                        // 論理座標へ変換
                        var lx = Math.max(0, Math.min(1, mouse.x / w));
                        var ly = Math.max(0, Math.min(1, 1 - mouse.y / h));
                        // slice() で配列をコピーして1要素だけ更新
                        var p = root.bezierParams.slice();
                        p[dragIdx] = lx;
                        p[dragIdx + 1] = ly;
                        root.bezierParams = p;
                    }
                    onReleased: {
                        dragIdx = -1;
                    }
                }

            }

        }

        GroupBox {
            title: "制御点"
            enabled: root.selectedType === "custom"

            GridLayout {
                columns: 4
                columnSpacing: 10

                Label {
                    text: "CP1 X"
                }

                TextField {
                    id: tfCp1x

                    text: root.bezierParams[0].toFixed(2)
                    onEditingFinished: {
                        var p = root.bezierParams.slice();
                        p[0] = Math.max(0, Math.min(1, parseFloat(text) || 0));
                        root.bezierParams = p;
                    }

                    // activeFocus 中は外部バインドを抑制
                    Binding on text {
                        when: !tfCp1x.activeFocus
                        value: root.bezierParams[0].toFixed(3)
                    }

                }

                Label {
                    text: "CP1 Y"
                }

                TextField {
                    id: tfCp1y

                    text: root.bezierParams[1].toFixed(2)
                    onEditingFinished: {
                        var p = root.bezierParams.slice();
                        p[1] = parseFloat(text) || 0;
                        root.bezierParams = p;
                    }

                    Binding on text {
                        when: !tfCp1y.activeFocus
                        value: root.bezierParams[1].toFixed(3)
                    }

                }

                Label {
                    text: "CP2 X"
                }

                TextField {
                    id: tfCp2x

                    text: root.bezierParams[2].toFixed(2)
                    onEditingFinished: {
                        var p = root.bezierParams.slice();
                        p[2] = Math.max(0, Math.min(1, parseFloat(text) || 0));
                        root.bezierParams = p;
                    }

                    Binding on text {
                        when: !tfCp2x.activeFocus
                        value: root.bezierParams[2].toFixed(3)
                    }

                }

                Label {
                    text: "CP2 Y"
                }

                TextField {
                    id: tfCp2y

                    text: root.bezierParams[3].toFixed(2)
                    onEditingFinished: {
                        var p = root.bezierParams.slice();
                        p[3] = parseFloat(text) || 0;
                        root.bezierParams = p;
                    }

                    Binding on text {
                        when: !tfCp2y.activeFocus
                        value: root.bezierParams[3].toFixed(3)
                    }

                }

            }

        }

    }

}

