    g_ctrl = static_cast<Rina::UI::TimelineController *>(controller);
    if (L) {
        _registerRinaAPI();

        // Export Host API Table
        lua_pushlightuserdata(L, &g_hostApi);
        lua_setglobal(L, "RINA_HOST_API");
    }
}

