// VST3 SDKの実装ファイルを直接インクルードしてシンボル未定義エラーを解消
#ifdef __clang__
#pragma clang diagnostic push
#pragma clang diagnostic ignored "-Wformat"
#pragma clang diagnostic ignored "-Wpragma-pack"
#endif
#include <pluginterfaces/base/funknown.cpp>
